143→body.font-small { --sub-font: 18px; --word-font: 22px; --trans-font: 15px; --def-font: 13px; --dict-input-font: 15px; }
144→body.font-medium { --sub-font: 22px; --word-font: 26px; --trans-font: 18px; --def-font: 15px; --dict-input-font: 18px; }
145→body.font-large { --sub-font: 28px; --word-font: 32px; --trans-font: 22px; --def-font: 18px; --dict-input-font: 22px; }
146→body.font-xlarge { --sub-font: 34px; --word-font: 38px; --trans-font: 26px; --def-font: 21px; --dict-input-font: 26px; }
147→
148→body {
149→    font-family: 'Microsoft YaHei UI', -apple-system, sans-serif;
150→    min-height: 100vh;
151→    background: var(--bg);
152→    overflow-y: auto;
153→    color: var(--text);
154→}
155→
156→.aurora-bg {
157→    position: fixed; top: 0; left: 0; width: 100%; height: 100%; z-index: -1;
158→    background: var(--bg-gradient);
159→}
160→.aurora-blob {
161→    position: absolute; border-radius: 50%; filter: blur(80px); opacity: var(--blob-opacity);
162→    animation: float 20s ease-in-out infinite;
163→}
164→.blob-1 { width: 500px; height: 500px; background: var(--blob1); top: -200px; left: -100px; }
165→.blob-2 { width: 400px; height: 400px; background: var(--blob2); top: 50%; right: -150px; animation-delay: -5s; }
166→.blob-3 { width: 450px; height: 450px; background: var(--blob3); bottom: -150px; left: 30%; animation-delay: -10s; }
167→@keyframes float {
168→    0%, 100% { transform: translate(0,0) scale(1); }
169→    25% { transform: translate(50px,-50px) scale(1.1); }
170→    50% { transform: translate(-30px,30px) scale(0.9); }
171→    75% { transform: translate(-50px,-30px) scale(1.05); }
172→}
173→
174→.container { display: flex; flex-direction: column; align-items: center; padding: 20px; min-height: 100vh; }
175→.header { text-align: center; margin-bottom: 15px; }
176→.title { font-size: 28px; color: var(--text); text-shadow: 0 2px 20px rgba(255,107,157,0.5); }
177→.subtitle { font-size: 13px; color: var(--accent); margin-top: 5px; }
178→
179→.glass-card {
180→    background: var(--glass-bg); backdrop-filter: blur(20px);
181→    border: 1px solid var(--glass-border); border-radius: 16px;
182→    box-shadow: 0 8px 32px rgba(0,0,0,0.3);
183→}
184→
185→/* 控制栏 */
186→.control-bar { width: 100%; max-width: 900px; padding: 15px 20px; margin-bottom: 15px; }
187→.input-row { display: flex; gap: 8px; align-items: center; flex-wrap: wrap; }
188→.input-row > * { height: 38px; line-height: 38px; box-sizing: border-box; }
189→.url-input {
190→    flex: 1; min-width: 180px; padding: 0 32px 0 14px; font-size: 13px; height: 38px; line-height: 38px;
191→    background: var(--input-bg); border: 1px solid var(--input-border);
192→    border-radius: 10px; color: var(--text); outline: none;
193→}
194→.url-input:focus { border-color: var(--accent); box-shadow: 0 0 15px rgba(255,107,157,0.3); }
195→.url-input::placeholder { color: var(--text-dim2); }
196→
197→.url-input-wrap {
198→    position: relative; flex: 1; min-width: 180px; display: flex;
199→}
200→.url-input-wrap .url-input { width: 100%; }
201→.clear-btn {
202→    position: absolute; right: 6px; top: 50%; transform: translateY(-50%);
203→    width: 22px; height: 22px; font-size: 12px; line-height: 22px; padding: 0;
204→    background: rgba(255,255,255,0.15); border: none; border-radius: 50%;
205→    color: var(--text-dim); cursor: pointer; display: flex; align-items: center; justify-content: center;
206→}
207→.clear-btn:hover { background: rgba(255,107,157,0.4); color: var(--text); }
208→
209→.paste-btn {
210→    width: 38px; height: 38px; font-size: 16px; line-height: 38px; padding: 0;
211→    background: var(--btn-secondary);
212→    border: none; border-radius: 10px; cursor: pointer; color: var(--text);
213→}
214→.paste-btn:hover { transform: scale(1.05); }
215→
216→.lang-select {
217→    padding: 0 10px; height: 38px; line-height: 38px; font-size: 13px; background: var(--input-bg);
218→    border: 1px solid var(--input-border); border-radius: 10px;
219→    color: var(--text); outline: none; cursor: pointer;
220→}
221→.lang-select option { background: var(--select-bg); color: var(--text); }
222→.video-select { flex: 1; min-width: 200px; }
223→
224→.label { font-size: 12px; color: var(--accent); font-weight: bold; margin-right: 8px; white-space: nowrap; }
225→
226→.progress-row { display: flex; align-items: center; gap: 10px; margin-top: 10px; }
227→.progress-bar { flex: 1; height: 8px; background: var(--input-bg); border-radius: 8px; overflow: hidden; }
228→.progress-fill { height: 100%; width: 0%; background: linear-gradient(90deg, var(--accent), var(--accent2), var(--accent3)); border-radius: 8px; transition: width 0.3s; }
229→.status-text { font-size: 12px; color: var(--text-dim); white-space: nowrap; }
230→
231→.video-list-row { display: flex; align-items: center; margin-top: 10px; gap: 8px; }
232→
233→/* 按钮 */
234→.btn {
235→    padding: 0 18px; height: 38px; line-height: 38px; font-size: 13px; font-weight: bold; color: #fff;
236→    border: none; border-radius: 10px; cursor: pointer; transition: all 0.3s; white-space: nowrap;
237→}
238→.btn-primary { background: var(--btn-primary); }
239→.btn-primary:hover { transform: translateY(-2px); box-shadow: 0 4px 20px rgba(255,51,102,0.5); }
240→.btn-small { padding: 0 14px; height: 38px; line-height: 38px; font-size: 13px; background: var(--btn-secondary); border-radius: 10px; }
241→.btn-small:hover { transform: translateY(-1px); }
242→.btn:disabled { opacity: 0.5; cursor: not-allowed; }
243→
244→/* 播放区 */
245→.player-area { width: 100%; max-width: 900px; padding: 15px; }
246→video { width: 100%; border-radius: 10px; background: #000; max-height: 450px; }
247→
248→/* 模式切换 */
249→.mode-bar { display: flex; gap: 8px; margin: 12px 0; }
250→.mode-btn {
251→    flex: 1; padding: 10px; font-size: 13px; color: var(--text); text-align: center;
252→    background: rgba(255,255,255,0.05); border: 1px solid var(--glass-border);
253→    border-radius: 10px; cursor: pointer; transition: all 0.3s;
254→}
255→.mode-btn:hover { background: rgba(255,255,255,0.1); }
256→.mode-btn.active { background: linear-gradient(135deg, rgba(255,107,157,0.3), rgba(138,43,226,0.3)); border-color: var(--accent); }
257→
258→/* 字幕区 */
259→.subtitle-area {
260→    min-height: 80px; padding: 15px; background: var(--sub-bg);
261→    border-radius: 12px; text-align: center;
262→}
263→.subtitle-text { font-size: var(--sub-font); color: var(--text); line-height: 2; }
264→.subtitle-text .word {
265→    cursor: pointer; padding: 2px 1px; border-radius: 4px; transition: background 0.2s;
266→    display: inline-block;
267→}
268→.subtitle-text .word:hover { background: var(--sub-hover); }
269→.subtitle-text .word.word-lit { color: #fff; background: var(--accent); border-radius: 4px; text-shadow: none; transition: all 0.08s; }
270→.subtitle-text .word.word-past { color: var(--accent); text-shadow: none; transition: color 0.15s; }
271→
272→/* 字幕滚动列表 */
273→.subtitle-list {
274→    max-height: 200px; overflow-y: auto; margin-top: 10px; padding: 8px;
275→    background: var(--sub-bg); border-radius: 10px;
276→}
277→.sub-list-item {
278→    display: flex; gap: 10px; padding: 6px 10px; border-radius: 6px;
279→    cursor: pointer; transition: background 0.2s; font-size: 13px;
280→}
281→.sub-list-item:hover { background: rgba(255,255,255,0.08); }
282→.sub-list-item.active { background: var(--sub-active-bg); border-left: 3px solid var(--sub-active-border); }
283→.sub-time { color: var(--text-dim2); white-space: nowrap; min-width: 40px; }
284→.sub-content { color: var(--text-dim); }
285→.sub-list-item.active .sub-content { color: var(--text); }
286→
287→/* 听写区 */
288→.dictation-area { padding: 15px; background: var(--sub-bg); border-radius: 12px; }
289→.dictation-sentence { display: flex; flex-wrap: wrap; gap: 6px; justify-content: center; margin-bottom: 12px; }
290→.dictation-sentence input {
291→    width: 80px; padding: 8px 10px; font-size: var(--dict-input-font); text-align: center;
292→    background: rgba(255,255,255,0.08); border: 1px solid var(--glass-border);
293→    border-radius: 6px; color: var(--text); outline: none;
294→}
295→.dictation-sentence input:focus { border-color: var(--accent3); box-shadow: 0 0 10px rgba(0,200,255,0.3); }
296→.dictation-sentence input.correct { border-color: #4ade80; background: rgba(74,222,128,0.15); }
297→.dictation-sentence input.wrong { border-color: #f87171; background: rgba(248,113,113,0.15); }
298→.dictation-sentence .answer-hint { font-size: 11px; color: #f87171; text-align: center; margin-top: 2px; }
299→.dict-word-group { display: flex; flex-direction: column; align-items: center; }
300→.dict-word-group .word-clickable {
301→    font-size: 11px; color: var(--text-dim2); cursor: pointer; margin-top: 2px;
302→}
303→.dict-word-group .word-clickable:hover { color: var(--accent); }
304→.dictation-controls { display: flex; gap: 8px; justify-content: center; }
305→
306→/* 音形义例句内联面板 - 精美卡片式 */
307→.word-inline-panel {
308→    margin-top: 14px; padding: 0; text-align: left;
309→    background: var(--word-panel-bg);
310→    border: 1px solid rgba(255,107,157,0.35); border-radius: 16px;
311→    animation: fadeIn 0.3s ease-out;
312→    box-shadow: 0 6px 30px rgba(0,0,0,0.4), inset 0 1px 0 rgba(255,255,255,0.06);
313→    overflow: hidden;
314→}
315→@keyframes fadeIn { from { opacity: 0; transform: translateY(-8px); } to { opacity: 1; transform: translateY(0); } }
316→
317→.word-card {
318→    display: flex; align-items: center; gap: 16px; padding: 18px 22px;
319→    background: var(--word-card-bg);
320→    border-bottom: 1px solid rgba(255,255,255,0.06);
321→}
322→.word-card-left { display: flex; flex-direction: column; gap: 4px; min-width: 120px; }
323→.word-card-word { font-size: var(--word-font); font-weight: 800; color: var(--accent); letter-spacing: 0.5px; }
324→.word-card-phonetic { font-size: var(--def-font); color: var(--text-dim); font-family: 'Lucida Sans Unicode', 'Segoe UI Symbol', 'DejaVu Sans', sans-serif; }
325→.word-card-speak {
326→    margin-top: 6px; padding: 6px 14px; font-size: 13px; color: #fff; width: fit-content;
327→    background: linear-gradient(135deg, rgba(6,182,212,0.4), rgba(138,43,226,0.4));
328→    border: 1px solid rgba(6,182,212,0.3); border-radius: 20px; cursor: pointer;
329→    transition: all 0.2s;
330→}
331→.word-card-speak:hover { transform: scale(1.05); box-shadow: 0 2px 12px rgba(6,182,212,0.4); }
332→.word-card-right { flex: 1; }
333→.word-card-trans { font-size: var(--trans-font); color: var(--text); line-height: 1.7; font-weight: 500; }
334→
335→.word-card-sections { padding: 14px 22px 16px; display: flex; gap: 16px; }
336→.word-card-section { flex: 1; }
337→.word-card-section-title {
338→    font-size: 13px; font-weight: bold; color: var(--text-dim2);
339→    letter-spacing: 1px; margin-bottom: 8px;
340→    padding-bottom: 6px; border-bottom: 1px solid rgba(255,255,255,0.06);
341→}
342→.word-card-section-body { font-size: var(--def-font); line-height: 1.9; }
343→.word-card-section-body .def-item {
344→    margin-bottom: 6px; padding: 6px 10px; color: var(--text);
345→    background: rgba(255,255,255,0.04); border-radius: 8px;
346→    border-left: 3px solid rgba(138,43,226,0.5);
347→}
348→.word-card-section-body .pos { color: var(--accent2); font-weight: bold; margin-right: 6px; }
349→.word-card-section-body .example {
350→    margin-bottom: 6px; padding: 6px 10px; color: var(--text-dim);
351→    background: rgba(255,107,157,0.04); border-radius: 8px;
352→    border-left: 3px solid rgba(255,107,157,0.4);
353→}
354→
355→/* 语音识别状态 */
356→.recognition-status { font-size: 11px; color: var(--accent3); margin-top: 6px; }
357→
358→/* 单词弹窗 */
359→.word-popup {
360→    position: fixed; z-index: 2000; width: 340px; max-height: 400px; overflow-y: auto;
361→    background: var(--popup-bg); backdrop-filter: blur(20px);
362→    border: 1px solid var(--input-border); border-radius: 14px;
363→    box-shadow: 0 10px 40px rgba(0,0,0,0.6); padding: 15px;
364→}
365→.popup-header { display: flex; align-items: center; gap: 8px; margin-bottom: 10px; }
366→.popup-word { font-size: 20px; font-weight: bold; color: var(--accent); }
367→.popup-phonetic { font-size: 13px; color: var(--text-dim); font-family: 'Lucida Sans Unicode', 'Segoe UI Symbol', 'DejaVu Sans', sans-serif; }
368→.popup-speak {
369→    font-size: 18px; background: none; border: none; cursor: pointer; padding: 2px;
370→}
