 255→async function loadVideo(videoPath, subtitlePath) {
 256→  playerArea.style.display = 'block';
 257→  currentVideoPath = videoPath;
 258→  videoPlayer.src = 'file:///' + videoPath.replace(/\\/g, '/');
 259→  subtitles = []; currentSubIndex = -1; wordTimings = null;
 260→  subtitleText.textContent = '加载字幕中...';
 261→  aiAnalyzeBtn.style.display = 'none';
 262→  aiResult.style.display = 'none';
 263→  const subtitleList = document.getElementById('subtitleList');
 264→  subtitleList.innerHTML = '';
 265→
 266→  let loaded = false;
 267→  // 优先尝试传入的字幕路径
 268→  if (subtitlePath) {
 269→    const vtt = await ipcRenderer.invoke('read-subtitle', subtitlePath);
 270→    if (vtt) {
 271→      subtitles = parseVTT(vtt);
 272→      if (subtitles.length > 0) {
 273→        buildSubtitleList();
 274→        subtitleText.textContent = `已加载 ${subtitles.length} 条字幕，播放视频即可同步显示`;
 275→        loaded = true;
 276→      }
 277→    }
 278→  }
 279→  // 没有传入字幕时，先检查同名.vtt是否已存在（之前转录过的）
 280→  if (!loaded) {
 281→    const existingVtt = await ipcRenderer.invoke('check-existing-subtitle', videoPath);
 282→    if (existingVtt) {
 283→      const vtt = await ipcRenderer.invoke('read-subtitle', existingVtt);
 284→      if (vtt) {
 285→        subtitles = parseVTT(vtt);
 286→        if (subtitles.length > 0) {
 287→          buildSubtitleList();
 288→          subtitleText.textContent = `已加载 ${subtitles.length} 条字幕，播放视频即可同步显示`;
 289→          loaded = true;
 290→        }
 291→      }
 292→    }
 293→  }
 294→  // 都没有才启动语音识别
 295→  if (!loaded) {
 296→    subtitleText.textContent = '无字幕文件，正在启动语音识别...';
 297→    const vttPath = await ipcRenderer.invoke('generate-subtitle', videoPath);
 298→    if (vttPath) {
 299→      const vtt = await ipcRenderer.invoke('read-subtitle', vttPath);
 300→      if (vtt) {
 301→        subtitles = parseVTT(vtt);
 302→        if (subtitles.length > 0) {
 303→          buildSubtitleList();
 304→          subtitleText.textContent = `语音识别完成，已生成 ${subtitles.length} 条字幕`;
 305→          loaded = true;
 306→        }
 307→      }
 308→    }
 309→    if (!loaded) subtitleText.textContent = '语音识别失败，请确认 funasr 服务已启动';
 310→  }
 311→  // 加载逐词时间戳（如果有）
 312→  const vttFile = subtitlePath || await ipcRenderer.invoke('check-existing-subtitle', videoPath);
 313→  if (vttFile) wordTimings = await ipcRenderer.invoke('read-word-timestamps', vttFile);
 314→}
