 368→              if (def.example) examples.push(def.example);
 369→            }
 370→          }
 371→          resolve({
 372→            phonetic: entry.phonetic || '',
 373→            audio: entry.phonetics?.find(p => p.audio)?.audio || '',
 374→            definitions: definitions.slice(0, 5),
 375→            examples: examples.slice(0, 5)
 376→          });
 377→        } catch(e) { resolve(null); }
